SELECT cargo_type 
FROM trip_details
WHERE trip_id = 0;

SELECT vessel_name, type
FROM vessels
WHERE vessel_id = 0;

SELECT SUM(amount * fuel_cost) AS total_fuel_cost
FROM fuel_consumption
WHERE trip_id = 1;

SELECT port_name, docking_fee
FROM ports
WHERE docking_fee = (
  SELECT MAX(docking_fee)
  FROM ports
);
